products.model:
'use strict';

function normalizeField(value, field) {
  if (typeof value !== 'string') {
    throw new TypeError(`invalid ${field}: expected string`);
  }
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`invalid ${field}: must be non-empty`);
  }
  return trimmed;
}

function normalizeBook(input) {
  if (input === null || typeof input !== 'object') {
    throw new TypeError('invalid book: expected object');
  }
  return {
    title: normalizeField(input.title, 'title'),
    author: normalizeField(input.author, 'author'),
  };
}

module.exports = { normalizeBook };

products.api:
'use strict';

const { normalizeBook } = require('./model.cjs');

function handleCreateBook(request) {
  try {
    const book = normalizeBook(request.body);
    return { status: 201, body: { book } };
  } catch (err) {
    if (err instanceof TypeError) {
      return { status: 400, body: { error: err.message } };
    }
    throw err;
  }
}

module.exports = { handleCreateBook };

